import { BrowserRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import React, { useState, useEffect } from 'react';
import Dashboard from './pages/Dashboard';
import LogManagement from './pages/LogManagement';
import AlertsCenter from './pages/AlertsCenter';
import Incidents from './pages/Incidents';
import RulesEngine from './pages/RulesEngine';
import Simulator from './pages/Simulator';
import MitreMapping from './pages/MitreMapping';
import Documentation from './pages/Documentation';
import Login from './pages/Login';
import { Shield, LayoutDashboard, Database, Activity, Briefcase, Settings, FileText, Target, Bell, X } from 'lucide-react';

function SidebarItem({ to, icon: Icon, label }) {
  const location = useLocation();
  const isActive = location.pathname === to;

  return (
    <Link to={to} className={`flex items-center px-4 py-3 rounded-lg transition-colors duration-200 mb-1 ${isActive ? 'bg-soc-primary/10 text-soc-primary box-shadow-glow' : 'text-soc-muted hover:bg-soc-border hover:text-soc-text'}`}>
      <Icon size={20} className="mr-3" />
      <span className="font-medium">{label}</span>
    </Link>
  );
}

function App() {
  const [liveAlerts, setLiveAlerts] = useState([]);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [alertEmail, setAlertEmail] = useState('');
  const [savingEmail, setSavingEmail] = useState(false);
  const [emailStatus, setEmailStatus] = useState('');
  const [isSidebarVisible, setIsSidebarVisible] = useState(true);

  // Fetch admin profile data when authenticated
  useEffect(() => {
    if (isAuthenticated && currentUser) {
      fetch(`http://localhost:8000/api/auth/profile/${currentUser}`)
        .then(res => res.json())
        .then(data => {
          if (data.alert_email) setAlertEmail(data.alert_email);
        })
        .catch(err => console.error("Error fetching profile", err));
    }
  }, [isAuthenticated, currentUser]);

  const saveProfile = async () => {
    setSavingEmail(true);
    try {
      const res = await fetch('http://localhost:8000/api/auth/profile', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username: currentUser, alert_email: alertEmail })
      });
      if (res.ok) {
        setEmailStatus('Saved successfully!');
        setTimeout(() => setEmailStatus(''), 2000);
      } else {
        setEmailStatus('Failed to save.');
      }
    } catch(err) {
      setEmailStatus('Error connecting to server.');
    }
    setSavingEmail(false);
  };

  useEffect(() => {
    // Connect to WebSocket purely for live toast notifications
    const ws = new WebSocket('ws://localhost:8000/api/logs/ws');

    ws.onopen = () => console.log("Connected to SOC real-time stream");

    ws.onmessage = (event) => {
      try {
        const payload = JSON.parse(event.data);
        if (payload.type === 'NEW_ALERT') {
           const newAlert = payload.data;
           setLiveAlerts(prev => [newAlert, ...prev].slice(0, 3)); // Display last 3

           // Auto-dismiss the alert after 5.5 seconds
           setTimeout(() => {
             setLiveAlerts(currentAlerts => currentAlerts.filter(a => a._id !== newAlert._id));
           }, 5500);
        }
      } catch (e) {
        console.error("Failed to parse websocket message", e);
      }
    };

    return () => {
      ws.close();
    };
  }, []);

  const dismissAlert = (id) => {
    setLiveAlerts(prev => prev.filter(a => a._id !== id));
  };

  if (!isAuthenticated) {
    return <Login onLogin={(username) => { setIsAuthenticated(true); setCurrentUser(username); }} />;
  }

  return (
    <Router>
      <div className="flex h-screen bg-soc-bg text-soc-text font-sans overflow-hidden">
        {/* Sidebar */}
        <div className={`fixed lg:relative left-0 top-0 h-full bg-soc-panel border-r border-soc-border flex flex-col shadow-2xl z-[100] transition-all duration-300 ease-in-out overflow-hidden ${isSidebarVisible ? 'w-64 translate-x-0' : 'w-0 -translate-x-full'}`}>
          {isSidebarVisible && (
            <>
              <div className="p-6 flex items-center mb-4 transition-opacity duration-200">
                <div className="w-8 h-8 rounded bg-gradient-to-br from-soc-primary to-blue-600 flex items-center justify-center mr-3 shadow-lg shadow-soc-primary/20">
                  <Shield size={18} className="text-white" />
                </div>
                <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-soc-text to-soc-muted">
                  CyberDetect
                </h1>
              </div>
              <nav className="flex-1 px-4 space-y-1">
                <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" />
                <SidebarItem to="/logs" icon={Database} label="Log Explorer" />
                <SidebarItem to="/alerts" icon={Activity} label="Alerts Center" />
                <SidebarItem to="/incidents" icon={Briefcase} label="Case Management" />
                <div className="pt-4 mt-4 border-t border-soc-border">
                  <p className="px-4 text-xs font-semibold text-soc-muted/50 uppercase tracking-wider mb-2">Simulate & Rules</p>
                  <SidebarItem to="/rules" icon={Settings} label="Detection Rules" />
                  <SidebarItem to="/mitre" icon={Target} label="MITRE ATT&CK" />
                  <SidebarItem to="/simulator" icon={Shield} label="Attack Simulator" />
                  <SidebarItem to="/docs" icon={FileText} label="Documentation" />
                </div>
              </nav>
              <div className="p-4 border-t border-soc-border text-xs text-soc-muted text-center">
                v1.0.0 SOC Environment
              </div>
            </>
          )}
        </div>

        {/* Main Content */}
        <div className="flex-1 flex flex-col relative w-full min-w-0">
          {/* Topbar */}
          <header className="h-16 bg-soc-panel/80 backdrop-blur-md border-b border-soc-border flex items-center justify-between px-8 absolute top-0 w-full z-[110]">
            <div className="flex items-center">
              <button 
                onClick={() => setIsSidebarVisible(!isSidebarVisible)}
                className="mr-4 p-2 text-soc-muted hover:bg-soc-border hover:text-white rounded-lg transition-all"
                title={isSidebarVisible ? "Hide Sidebar" : "Show Sidebar"}
              >
                <LayoutDashboard size={20} className={isSidebarVisible ? "" : "text-soc-primary animate-pulse"} />
              </button>
              <span className="font-medium text-soc-text">Security Operations Center</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="text-sm text-soc-muted text-right">
                <div className="font-medium text-soc-success flex items-center justify-end">
                  <div className="w-2 h-2 rounded-full bg-soc-success mr-2 animate-pulse"></div>
                   Connection Active
                </div>
              </div>
              <div className="w-8 h-8 rounded-full bg-soc-border overflow-hidden border border-soc-border cursor-pointer hover:ring-2 hover:ring-soc-primary transition-all" onClick={() => setShowProfileMenu(!showProfileMenu)}>
                <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Analyst" alt="User" />
              </div>
            </div>
          </header>

          <main className="flex-1 overflow-auto bg-soc-bg p-8 pt-24 custom-scrollbar">
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/logs" element={<LogManagement />} />
              <Route path="/alerts" element={<AlertsCenter />} />
              <Route path="/incidents" element={<Incidents />} />
              <Route path="/rules" element={<RulesEngine />} />
              <Route path="/mitre" element={<MitreMapping />} />
              <Route path="/simulator" element={<Simulator />} />
              <Route path="/docs" element={<Documentation />} />
            </Routes>
          </main>

          {/* Profile Modal Overlay */}
          {showProfileMenu && (
            <div className="absolute top-16 right-8 w-80 bg-soc-panel border border-soc-border rounded-lg shadow-2xl z-50 overflow-hidden transform transition-all">
              <div className="p-4 border-b border-soc-border bg-gradient-to-r from-soc-bg to-soc-panel flex items-center space-x-3">
                <div className="w-10 h-10 rounded-full bg-soc-border overflow-hidden border border-soc-border">
                  <img src="https://api.dicebear.com/7.x/avataaars/svg?seed=Analyst" alt="User" />
                </div>
                <div>
                  <p className="font-bold text-soc-text">{currentUser || 'SOC Admin'}</p>
                  <p className="text-xs text-soc-success">Online & Authenticated</p>
                </div>
              </div>
              <div className="p-4">
                <h4 className="text-sm font-semibold text-soc-muted mb-3 uppercase tracking-wider">Notification Settings</h4>
                <div className="space-y-3">
                  <div>
                    <label className="block text-xs font-medium text-soc-text mb-1">Critical Alert Email Recipient</label>
                    <input 
                      type="email" 
                      value={alertEmail}
                      onChange={(e) => setAlertEmail(e.target.value)}
                      placeholder="admin@cyberdetect.local"
                      className="w-full bg-soc-bg border border-soc-border rounded px-3 py-2 text-sm text-soc-text focus:outline-none focus:border-soc-primary transition-colors"
                    />
                  </div>
                  <button 
                    onClick={saveProfile}
                    disabled={savingEmail}
                    className="w-full bg-soc-primary hover:bg-blue-600 text-white font-medium py-2 rounded text-sm transition-colors"
                  >
                    {savingEmail ? 'Saving...' : 'Save Preferences'}
                  </button>
                  {emailStatus && <p className={`text-xs text-center mt-2 ${emailStatus.includes('success') ? 'text-soc-success' : 'text-soc-danger'}`}>{emailStatus}</p>}
                </div>
              </div>
            </div>
          )}

          {/* Live Alerts Toast Container */}
          <div className="fixed bottom-6 right-6 z-50 flex flex-col space-y-3">
             {liveAlerts.map(alert => (
               <div key={alert._id} className="bg-soc-panel border-l-4 border-soc-danger text-soc-text p-4 rounded shadow-2xl w-80 flex items-start justify-between animate-toast">
                 <div className="flex items-start">
                   <Bell size={18} className="text-soc-danger mr-3 mt-1" />
                   <div>
                     <h4 className="font-bold text-sm">New Alert Detected</h4>
                     <p className="text-xs text-soc-muted mt-1">{alert.rule_name}</p>
                     <p className="text-xs text-soc-danger font-bold mt-1 uppercase">{alert.severity}</p>
                   </div>
                 </div>
                 <button onClick={() => dismissAlert(alert._id)} className="text-soc-muted hover:text-white">
                   <X size={16} />
                 </button>
               </div>
             ))}
          </div>
        </div>
      </div>
    </Router>
  );
}

export default App;

import React from 'react';
import { Radar, Target, Zap, Shield, Activity, Lock, FlaskConical } from 'lucide-react';

const KILL_CHAIN_PHASES = [
  { id: 'recon', name: 'Reconnaissance', icon: Radar, color: 'text-blue-400', tactic: ['TA0007', 'TA0043'] },
  { id: 'weaponization', name: 'Weaponization', icon: FlaskConical, color: 'text-indigo-400', tactic: ['TA0042'] },
  { id: 'delivery', name: 'Delivery', icon: Zap, color: 'text-yellow-400', tactic: ['TA0001'] },
  { id: 'exploitation', name: 'Exploitation', icon: Activity, color: 'text-orange-400', tactic: ['TA0002', 'TA0004'] },
  { id: 'installation', name: 'Installation', icon: Shield, color: 'text-purple-400', tactic: ['TA0003', 'TA0005'] },
  { id: 'c2', name: 'C&C', icon: Target, color: 'text-red-400', tactic: ['TA0011'] },
  { id: 'actions', name: 'Actions', icon: Lock, color: 'text-red-600', tactic: ['TA0040', 'TA0010'] }
];

export default function KillChainVisualization({ activeTactics = [] }) {
  // activeTactics is an array of MITRE tactic IDs or technique names matched for this incident

  return (
    <div className="w-full bg-soc-bg/30 border border-soc-border rounded-xl p-6 shadow-2xl">
      <h3 className="text-sm font-bold text-soc-text mb-6 uppercase tracking-widest flex items-center">
        <Activity size={16} className="mr-2 text-soc-primary" />
        Attack Kill-Chain Lifecycle
      </h3>

      <div className="relative flex items-center justify-between">
        {/* Background Connector Line */}
        <div className="absolute top-1/2 left-0 w-full h-0.5 bg-soc-border -translate-y-1/2 z-0"></div>

        {KILL_CHAIN_PHASES.map((phase, index) => {
          const isActive = phase.tactic.some(t => activeTactics.includes(t));
          const Icon = phase.icon;

          return (
            <div key={phase.id} className="relative z-10 flex flex-col items-center">
              {/* phase indicator circle */}
              <div className={`w-12 h-12 rounded-full border-2 flex items-center justify-center transition-all duration-500 mb-2 
                ${isActive 
                  ? `${phase.color.replace('text', 'border')} bg-soc-panel scale-125 box-shadow-glow` 
                  : 'bg-soc-bg border-soc-border scale-100 opacity-40 grayscale'}`}
                title={phase.name}
              >
                <Icon size={20} className={isActive ? phase.color : 'text-soc-muted'} />
              </div>

              {/* phase label */}
              <div className="text-center">
                <p className={`text-[10px] font-bold uppercase tracking-tighter ${isActive ? 'text-soc-text' : 'text-soc-muted opacity-50'}`}>
                  {phase.name}
                </p>
                {isActive && (
                  <span className="w-1.5 h-1.5 rounded-full bg-soc-primary inline-block absolute -bottom-2 translate-x-1/2 right-1/2 animate-pulse"></span>
                )}
              </div>

              {/* Step indicator */}
              <div className="absolute -top-6 text-[8px] font-mono text-soc-muted/30">
                STAGE {index + 1}
              </div>
            </div>
          );
        })}
      </div>

      {activeTactics.length > 0 && (
        <div className="mt-8 flex items-center justify-center space-x-4 animate-in fade-in slide-in-from-bottom-2 duration-700">
           <div className="h-px w-12 bg-gradient-to-r from-transparent to-soc-primary/50"></div>
           <p className="text-[11px] text-soc-muted italic">
             Adversary has reached the <span className="text-soc-danger font-bold uppercase">{KILL_CHAIN_PHASES.filter(p => p.tactic.some(t => activeTactics.includes(t))).pop()?.name}</span> phase
           </p>
           <div className="h-px w-12 bg-gradient-to-l from-transparent to-soc-primary/50"></div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { ShieldAlert, CheckCircle, Clock, X, AlertTriangle, Activity, Lock, Search, Filter, Globe, Database, ShieldCheck, ShieldX, Zap } from 'lucide-react';

export default function AlertsCenter() {
  const [allAlerts, setAllAlerts] = useState([]);
  const [statusFilter, setStatusFilter] = useState('active');
  const [severityFilter, setSeverityFilter] = useState('all');
  const [loading, setLoading] = useState(true);
  const [investigatingAlert, setInvestigatingAlert] = useState(null);
  const [intelData, setIntelData] = useState(null);
  const [fetchingIntel, setFetchingIntel] = useState(false);
  const [intelError, setIntelError] = useState(null);
  const [soarRunning, setSoarRunning] = useState({}); // {actionName: true/false}
  const [soarSuccess, setSoarSuccess] = useState({}); // {actionName: msg}
  const [soarError, setSoarError] = useState(null);

  useEffect(() => {
    fetch('http://localhost:8000/api/alerts')
      .then(res => res.json())
      .then(data => {
        setAllAlerts(data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Error fetching alerts:", err);
        setLoading(false);
      });

    // Real-time alert updates
    const ws = new WebSocket('ws://localhost:8000/api/logs/ws');
    ws.onmessage = (event) => {
      try {
        const payload = JSON.parse(event.data);
        if (payload.type === 'NEW_ALERT') {
          setAllAlerts(prev => [payload.data, ...prev]);
        }
      } catch (e) {
        console.error("WS error in AlertsCenter:", e);
      }
    };
    return () => ws.close();
  }, []);

  const handleStatusChange = async (id, newStatus) => {
    try {
      const res = await fetch(`http://localhost:8000/api/alerts/${id}/status?status=${newStatus}`, {
        method: 'PUT'
      });
      if (res.ok) {
        setAllAlerts(prev => prev.map(a => a.id === id ? { ...a, status: newStatus } : a));
        if (investigatingAlert?.id === id) setInvestigatingAlert(null);
      }
    } catch (err) {
      console.error("Failed to update status", err);
    }
  };

  const startInvestigation = (alert) => {
    setInvestigatingAlert(alert);
    setIntelData(null); // Reset intel when opening new investigation
  };

  const fetchThreatIntel = async (ip) => {
    if (!ip || ip === 'N/A' || ip === 'Unknown') {
      setIntelError("No valid IP address found for enrichment.");
      return;
    }
    setFetchingIntel(true);
    setIntelError(null);
    setIntelData(null);
    try {
      const res = await fetch(`http://localhost:8000/api/intel/lookup/${encodeURIComponent(ip)}`);
      if (res.ok) {
        const data = await res.json();
        setIntelData(data);
      } else {
        setIntelError(`Failed to fetch intelligence: ${res.status} ${res.statusText}`);
      }
    } catch (err) {
      console.error("TI lookup failed", err);
      setIntelError("Could not connect to Threat Intelligence service.");
    }
    setFetchingIntel(false);
  };

  const triggerSoarAction = async (action, target) => {
    if (!target || target === 'N/A' || target === 'Unknown') {
      setSoarError(`Invalid target for ${action}: No valid identifier found.`);
      return;
    }
    setSoarRunning(prev => ({ ...prev, [action]: true }));
    setSoarSuccess(prev => ({ ...prev, [action]: null }));
    setSoarError(null);

    try {
      const endpoint = action === 'quarantine' ? `quarantine/${encodeURIComponent(target)}` : `ban-ip/${encodeURIComponent(target)}`;
      const res = await fetch(`http://localhost:8000/api/soar/${endpoint}`, { 
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
      });
      if (res.ok) {
        const data = await res.json();
        setSoarSuccess(prev => ({ ...prev, [action]: data.message }));
      } else {
        const errData = await res.json().catch(() => ({ detail: 'Unknown error' }));
        setSoarError(`SOAR Execution Failed: ${errData.detail || res.statusText}`);
      }
    } catch (err) {
      console.error("SOAR action failed", err);
      setSoarError("Failed to connect to SOAR orchestration service.");
    }
    setSoarRunning(prev => ({ ...prev, [action]: false }));
  };

  const filteredAlerts = allAlerts.filter(a => {
    let sMatch = true;
    if (statusFilter === 'active') { sMatch = ['new', 'investigating'].includes(a.status); }
    else if (statusFilter !== 'all') { sMatch = a.status === statusFilter; }

    let sevMatch = true;
    if (severityFilter !== 'all') { sevMatch = a.severity?.toLowerCase() === severityFilter; }

    return sMatch && sevMatch;
  });

  const formatTime = (timeStr) => {
    if (!timeStr) return 'N/A';
    const dateStr = timeStr.endsWith('Z') || timeStr.includes('+') ? timeStr : timeStr.replace(' ', 'T') + 'Z';
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? 'N/A' : date.toLocaleString();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-soc-text">Alerts Center</h2>
          <p className="text-sm text-soc-muted mt-1">Review and triage security detections</p>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row space-y-3 sm:space-y-0 sm:space-x-4 bg-soc-panel p-4 rounded-lg border border-soc-border shadow-lg">
        <div className="flex items-center">
            <Filter size={18} className="text-soc-muted mr-3" />
            <span className="text-soc-text font-medium text-sm">Filters:</span>
        </div>
        <div>
          <select 
            className="bg-soc-bg border border-soc-border rounded px-3 py-1.5 text-sm text-soc-text w-full sm:w-auto outline-none transition-colors hover:border-soc-primary focus:border-soc-primary cursor-pointer"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="all">All Statuses</option>
            <option value="active">Active (New / Investigating)</option>
            <option value="resolved">Resolved</option>
            <option value="false_positive">False Positives</option>
          </select>
        </div>
        <div>
          <select 
            className="bg-soc-bg border border-soc-border rounded px-3 py-1.5 text-sm text-soc-text w-full sm:w-auto outline-none transition-colors hover:border-soc-primary focus:border-soc-primary cursor-pointer"
            value={severityFilter}
            onChange={(e) => setSeverityFilter(e.target.value)}
          >
            <option value="all">Any Severity</option>
            <option value="critical">Critical Only</option>
            <option value="high">High Only</option>
            <option value="medium">Medium Only</option>
            <option value="low">Low Only</option>
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {loading ? (
          <div className="text-soc-muted text-center py-8">Loading alerts...</div>
        ) : filteredAlerts.length === 0 ? (
           <div className="text-soc-muted text-center py-8 bg-soc-panel border border-soc-border rounded-lg shadow-lg">No alerts match the current filters.</div>
        ) : (
          filteredAlerts.map(alert => (
            <div key={alert.id} className="bg-soc-panel border-l-4 border border-soc-border rounded-lg p-5 flex flex-col sm:flex-row sm:items-center justify-between shadow-lg hover:bg-soc-bg/40 transition-colors"
                 style={{ borderLeftColor: alert.severity === 'critical' ? '#991B1B' : alert.severity === 'high' ? '#EF4444' : '#F59E0B' }}>
              <div>
                <div className="flex items-center space-x-3 mb-2">
                  <span className={`px-2 py-0.5 rounded text-xs font-bold bg-soc-bg border
                    ${alert.severity === 'critical' ? 'text-soc-critical border-soc-critical/50' : 
                      alert.severity === 'high' ? 'text-soc-danger border-soc-danger/50' : 
                      'text-soc-warning border-soc-warning/50'}`}>
                    {alert.severity.toUpperCase()}
                  </span>
                  <h3 className="text-lg font-semibold text-soc-text">{alert.rule_name}</h3>
                </div>
                <div className="flex items-center space-x-6 text-sm text-soc-muted">
                  <span className="flex items-center"><Clock size={14} className="mr-1" /> {formatTime(alert.triggered_time)}</span>
                  <span><strong>MITRE:</strong> <span className="text-soc-primary hover:underline cursor-pointer">{alert.mitre_attack_id}</span></span>
                  {alert.source_ip && <span><strong>Source:</strong> <span className="font-mono">{alert.source_ip}</span></span>}
                  {alert.affected_host && <span><strong>Host:</strong> <span className="font-mono">{alert.affected_host}</span></span>}
                </div>
                {alert.threat_intel && (
                  <div className="mt-3 text-xs bg-soc-bg p-2 rounded border border-soc-border flex items-center space-x-4">
                    <span className="font-semibold text-soc-muted">Threat Intel:</span>
                    <span className={alert.threat_intel?.score > 50 ? 'text-soc-success' : 'text-soc-danger'}>
                      Status: {alert.threat_intel?.status || 'N/A'}
                    </span>
                    {alert.threat_intel?.score !== undefined && (
                        <span>Score: {alert.threat_intel.score}/100</span>
                    )}
                  </div>
                )}
              </div>
              <div className="mt-4 sm:mt-0 flex space-x-2">
                <button 
                  onClick={() => startInvestigation(alert)}
                  className="px-3 py-1.5 bg-soc-bg border border-soc-border rounded hover:border-soc-primary text-sm transition-colors hover:text-soc-primary shadow-sm"
                >
                  <Search size={14} className="inline mr-1" /> Investigate
                </button>
                <button 
                  onClick={() => handleStatusChange(alert.id, 'resolved')}
                  className="px-3 py-1.5 bg-soc-success/10 text-soc-success border border-soc-success/30 rounded hover:bg-soc-success/20 text-sm transition-colors shadow-sm"
                >
                  <CheckCircle size={14} className="inline mr-1" /> Resolve
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Investigation Modal */}
      {investigatingAlert && (
