import React, { useState, useEffect } from 'react';
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { ShieldAlert, Activity, Users, Database, Maximize2, X } from 'lucide-react';

const COLORS = ['#10B981', '#F59E0B', '#EF4444', '#991B1B'];

export default function Dashboard() {
  const [alerts, setAlerts] = useState([]);
  const [logsCount, setLogsCount] = useState(0);
  const [expandedChart, setExpandedChart] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [alertsRes, logsRes] = await Promise.all([
          fetch('http://localhost:8000/api/alerts'),
          fetch('http://localhost:8000/api/logs?limit=100')
        ]);
        const alertsData = await alertsRes.json();
        const logsData = await logsRes.json();
        setAlerts(alertsData);
        setLogsCount(logsData.length > 0 ? (124000 + logsData.length) : 124500); // Mock large base log volume + real logs
      } catch (e) {
        console.error("Failed to load dashboard stats", e);
      }
    };
    fetchStats();
  }, []);

  const activeAlerts = alerts.filter(a => a.status === 'new' || a.status === 'investigating').length;
  const criticalAlerts = alerts.filter(a => a.severity === 'Critical' || a.severity === 'critical').length;

  // Calculate severity distribution
  const rawSeverity = alerts.reduce((acc, a) => {
    // Normalize casing for display
    const sev = a.severity ? a.severity.charAt(0).toUpperCase() + a.severity.slice(1).toLowerCase() : 'Unknown';
    acc[sev] = (acc[sev] || 0) + 1;
    return acc;
  }, {});

  const severityData = [
    { name: 'Low', value: rawSeverity['Low'] || 0 },
    { name: 'Medium', value: rawSeverity['Medium'] || 0 },
    { name: 'High', value: rawSeverity['High'] || 0 },
    { name: 'Critical', value: rawSeverity['Critical'] || 0 }
  ].filter(d => d.value > 0);

  if (severityData.length === 0) {
    severityData.push({ name: 'No Alerts (Healthy)', value: 1 });
  }

  // Calculate alerts by rule for Bar Chart
  const alertsByRule = alerts.reduce((acc, a) => {
    const key = a.rule_name || 'Unknown Rule';
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});

  const ruleData = Object.keys(alertsByRule).map(key => ({
    rule: key.length > 15 ? key.substring(0, 15) + "..." : key,
    fullRule: key,
    count: alertsByRule[key]
  }));

  const renderBarChart = (isExpanded = false) => (
    <ResponsiveContainer width="100%" height="100%">
      {ruleData.length > 0 ? (
        <BarChart data={ruleData} margin={{ top: 10, right: 30, left: 0, bottom: isExpanded ? 50 : 0 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
          <XAxis dataKey={isExpanded ? "fullRule" : "rule"} stroke="#94A3B8" tick={{ fontSize: 12 }} angle={isExpanded ? -45 : 0} textAnchor={isExpanded ? "end" : "middle"} />
          <YAxis stroke="#94A3B8" allowDecimals={false} />
          <Tooltip cursor={{fill: '#334155', opacity: 0.4}} contentStyle={{ backgroundColor: '#1E293B', borderColor: '#334155', borderRadius: '8px' }} labelFormatter={(label, payload) => payload?.[0]?.payload?.fullRule || label} />
          <Bar dataKey="count" fill="#3B82F6" name="Total Triggered" radius={[4, 4, 0, 0]} />
        </BarChart>
      ) : (
        <div className="flex h-full items-center justify-center text-soc-muted">No alerts detected yet. Run simulations to populate this chart.</div>
      )}
    </ResponsiveContainer>
  );

  const renderPieChart = () => (
    <ResponsiveContainer width="100%" height="100%">
      <PieChart>
        <Pie
          data={severityData}
          cx="50%"
          cy="50%"
          innerRadius={expandedChart === 'pie' ? 100 : 60}
          outerRadius={expandedChart === 'pie' ? 140 : 80}
          paddingAngle={5}
          dataKey="value"
        >
          {severityData.map((entry, index) => (
            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
          ))}
        </Pie>
        <Tooltip contentStyle={{ backgroundColor: '#1E293B', borderColor: '#334155' }} />
      </PieChart>
    </ResponsiveContainer>
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-soc-text">SOC Overview</h2>
        <span className="text-sm text-soc-muted">Last updated: Just now</span>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-soc-panel border border-soc-border p-6 rounded-lg shadow-lg lg:col-span-1 md:col-span-2">
          <div className="flex items-center space-x-4">
             <div className="p-4 bg-soc-primary/10 rounded-full text-soc-primary">
               <Database size={28} />
             </div>
             <div>
               <p className="text-sm font-medium text-soc-muted">Total Logs (24h)</p>
               <h3 className="text-2xl font-bold mt-1 text-soc-text">{logsCount.toLocaleString()}</h3>
             </div>
          </div>
        </div>

        <div className="bg-soc-panel border border-soc-border p-6 rounded-lg shadow-lg">
          <div className="flex items-center space-x-4">
             <div className="p-4 bg-soc-warning/10 rounded-full text-soc-warning">
               <Activity size={28} />
             </div>
             <div>
               <p className="text-sm font-medium text-soc-muted">Active Alerts</p>
               <h3 className="text-2xl font-bold mt-1 text-soc-text">{activeAlerts}</h3>
             </div>
          </div>
        </div>

        <div className="bg-soc-panel border border-soc-border p-6 rounded-lg shadow-lg">
          <div className="flex items-center space-x-4">
             <div className="p-4 bg-soc-critical/10 rounded-full text-soc-critical">
               <ShieldAlert size={28} />
             </div>
             <div>
               <p className="text-sm font-medium text-soc-muted">Critical Alerts</p>
               <h3 className="text-2xl font-bold mt-1 text-soc-text">{criticalAlerts}</h3>
             </div>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-soc-panel border border-soc-border p-6 rounded-lg shadow-lg lg:col-span-2">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-soc-text">Alerts by Detection Rule</h3>
            <button onClick={() => setExpandedChart('bar')} className="text-soc-muted hover:text-white transition-colors" title="Expand Chart">
              <Maximize2 size={18} />
            </button>
          </div>
          <div className="h-72">
            {renderBarChart()}
          </div>
        </div>

        <div className="bg-soc-panel border border-soc-border p-6 rounded-lg shadow-lg">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-semibold text-soc-text">Alerts by Severity</h3>
             <button onClick={() => setExpandedChart('pie')} className="text-soc-muted hover:text-white transition-colors" title="Expand Chart">
              <Maximize2 size={18} />
            </button>
          </div>
          <div className="h-72 flex flex-col items-center">
            <div className="flex-1 w-full">
               {renderPieChart()}
            </div>
            <div className="flex justify-center space-x-4 mt-4 w-full flex-wrap">
              {severityData.map((entry, index) => (
                <div key={entry.name} className="flex items-center text-xs mb-2">
                  <div className="w-3 h-3 rounded-full mr-2" style={{ backgroundColor: COLORS[index] }}></div>
                  <span className="text-soc-muted">{entry.name} ({entry.value})</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Expanded Chart Modal */}
      {expandedChart && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md flex items-center justify-center z-[100] p-8">
          <div className="bg-soc-panel border border-soc-border rounded-lg shadow-2xl w-full max-w-6xl h-[80vh] flex flex-col">
            <div className="flex justify-between items-center p-6 border-b border-soc-border">
              <h3 className="text-2xl font-bold text-soc-text">
                {expandedChart === 'bar' ? 'Detailed Analysis: Alerts by Detection Rule' : 'Detailed Analysis: Alerts by Severity'}
              </h3>
              <button onClick={() => setExpandedChart(null)} className="p-2 text-soc-muted hover:bg-soc-border hover:text-white rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>
            <div className="flex-1 p-8 min-h-0">
               {expandedChart === 'bar' && renderBarChart(true)}
               {expandedChart === 'pie' && (
                 <div className="h-full flex flex-col items-center justify-center">
                    <div className="h-[500px] w-full max-w-2xl">
                      {renderPieChart()}
                    </div>
                    <div className="flex justify-center space-x-8 mt-8 text-lg">
                      {severityData.map((entry, index) => (
                        <div key={entry.name} className="flex items-center">
                          <div className="w-4 h-4 rounded-full mr-3 shadow-[0_0_10px_rgba(0,0,0,0.5)]" style={{ backgroundColor: COLORS[index] }}></div>
                          <span className="text-white font-medium">{entry.name}</span>
                          <span className="ml-2 text-soc-muted">({entry.value} occurrences)</span>
                        </div>
                      ))}
                    </div>
                 </div>
               )}
            </div>
            <div className="p-4 border-t border-soc-border bg-soc-bg rounded-b-lg text-sm text-soc-muted flex items-center">
               <Activity size={16} className="mr-2 text-soc-primary" />
               Dataset updated dynamically via Live WebSockets. Interactive charting powered by Recharts.
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Briefcase, User, MessageSquare, Clock, X, CheckCircle, AlertCircle, Plus, Send, Shield, Activity, Target } from 'lucide-react';
import KillChainVisualization from '../components/KillChainVisualization';

export default function Incidents() {
  const [incidents, setIncidents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCase, setSelectedCase] = useState(null);
  const [newNote, setNewNote] = useState('');
  const [submittingNote, setSubmittingNote] = useState(false);
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [newCaseData, setNewCaseData] = useState({
    title: '',
    severity: 'medium',
    analyst_assigned: 'SOC Analyst',
  });
  const [creatingCase, setCreatingCase] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  useEffect(() => {
    fetchIncidents();
  }, []);

  const fetchIncidents = () => {
    setLoading(true);
    fetch('http://localhost:8000/api/incidents')
      .then(res => res.json())
      .then(data => {
        setIncidents(data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Error fetching incidents:", err);
        setLoading(false);
      });
  };

  const handleCreateCase = async (e) => {
    e.preventDefault();
    if (!newCaseData.title.trim()) return;
    setCreatingCase(true);
    try {
      const payload = {
        ...newCaseData,
        case_id: "PENDING", // Backend will generate CAS-XXXX
        status: "open",
        alerts_linked: [],
        notes: [],
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
      };
      const res = await fetch('http://localhost:8000/api/incidents', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      if (res.ok) {
        setIsCreateModalOpen(false);
        setNewCaseData({ title: '', severity: 'medium', analyst_assigned: 'SOC Analyst' });
        fetchIncidents();
      }
    } catch (err) {
      console.error("Failed to create case", err);
    }
    setCreatingCase(false);
  };

  const openCaseDetails = (inc) => {
    setSelectedCase(inc);
    setAiAnalysis(null); // Reset analysis when opening new case
  };

  const runAIAnalysis = async () => {
    if (!selectedCase) return;
    setIsAnalyzing(true);
    setAiAnalysis(null);
    try {
      const res = await fetch(`http://localhost:8000/api/incidents/${selectedCase.id}/ai-analyze`, {
        method: 'POST'
      });
      if (res.ok) {
        const data = await res.json();
        setAiAnalysis(data.analysis);
      }
    } catch (err) {
      console.error("AI Analysis failed", err);
    }
    setIsAnalyzing(false);
  };

  const handleStatusUpdate = async (id, newStatus) => {
    try {
      const res = await fetch(`http://localhost:8000/api/incidents/${id}/status?status=${newStatus}`, {
        method: 'PUT'
      });
      if (res.ok) {
        setIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status: newStatus } : inc));
        if (selectedCase?.id === id) {
          setSelectedCase({ ...selectedCase, status: newStatus });
        }
      }
    } catch (err) {
      console.error("Failed to update case status", err);
    }
  };

  const submitNote = async () => {
    if (!newNote.trim() || !selectedCase) return;
    setSubmittingNote(true);
    try {
      const res = await fetch(`http://localhost:8000/api/incidents/${selectedCase.id}/notes?note_content=${encodeURIComponent(newNote)}`, {
        method: 'PUT'
      });
      if (res.ok) {
        const addedNote = await res.json();
        const updatedCase = {
          ...selectedCase,
          notes: [...(selectedCase.notes || []), addedNote]
        };
        setSelectedCase(updatedCase);
        setIncidents(prev => prev.map(inc => inc.id === selectedCase.id ? updatedCase : inc));
        setNewNote('');
      }
    } catch (err) {
      console.error("Failed to add note", err);
    }
    setSubmittingNote(false);
  };
  const getTacticsFromMapping = (mappings) => {
    if (!mappings) return [];
    const techToTactic = {
      'T1003': 'TA0006',
      'T1110': 'TA0006',
      'T1047': 'TA0008',
      'T1059': 'TA0002',
      'T1547': 'TA0003',
      'T1053': 'TA0003',
      'T1562': 'TA0005',
      'T1105': 'TA0001',
      'T1041': 'TA0010',
      'T1486': 'TA0040',
      'T1548': 'TA0004'
    };

    const tactics = new Set();
    mappings.forEach(m => {
      const tid = m.match(/T\d+/)?.[0];
      if (tid && techToTactic[tid]) {
        tactics.add(techToTactic[tid]);
      }
    });
    return Array.from(tactics);
  };
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-soc-text">Case Management</h2>
          <p className="text-sm text-soc-muted mt-1">Track and investigate escalated security incidents</p>
        </div>
        <button 
          onClick={() => setIsCreateModalOpen(true)}
          className="px-4 py-2 bg-soc-primary text-white rounded hover:bg-blue-600 transition-colors text-sm shadow-lg shadow-soc-primary/20 flex items-center"
        >
          <Plus size={16} className="mr-2" /> New Case
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {loading ? (
          <div className="text-soc-muted p-4 col-span-full text-center">Loading cases...</div>
        ) : incidents.length === 0 ? (
          <div className="bg-soc-panel border border-soc-border p-12 rounded-lg text-center text-soc-muted col-span-full shadow-lg">
            <Briefcase size={48} className="mx-auto mb-4 opacity-20" />
            <p className="text-lg">No active incidents.</p>
            <p className="text-sm mt-1">Escalate alerts to create a new case.</p>
          </div>
        ) : (
          incidents.map(inc => (
            <div key={inc.id} className="bg-soc-panel border border-soc-border rounded-lg shadow-lg hover:shadow-soc-primary/5 transition-all group overflow-hidden">
              <div className="p-5 border-b border-soc-border bg-gradient-to-br from-soc-panel to-soc-bg/50">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-xs font-mono bg-soc-bg px-2 py-1 rounded text-soc-muted border border-soc-border">
                    {inc.case_id}
                  </span>
                  <span className={`text-xs font-bold px-2 py-1 rounded ${
                    inc.severity === 'critical' ? 'text-soc-critical bg-soc-critical/10' : 
                    inc.severity === 'high' ? 'text-soc-danger bg-soc-danger/10' : 
                    'text-soc-warning bg-soc-warning/10'
                  }`}>
                    {inc.severity.toUpperCase()}
                  </span>
                </div>
                <h3 className="font-semibold text-lg text-soc-text block truncate" title={inc.title}>{inc.title}</h3>
              </div>
              <div className="p-5 bg-soc-bg/30 space-y-4">
                <div className="flex items-center justify-between text-sm text-soc-muted">
                  <span className="flex items-center"><User size={14} className="mr-2 text-soc-primary" /> {inc.analyst_assigned || 'Unassigned'}</span>
                  <span className="flex items-center"><MessageSquare size={14} className="mr-1 text-soc-primary" /> {inc.notes?.length || 0} Notes</span>
                </div>
                <div className="flex items-center justify-between text-sm pt-2 border-t border-soc-border/30">
                  <span className={`font-medium px-2 py-0.5 rounded-full text-xs box-shadow-glow ${
                    inc.status === 'open' ? 'bg-soc-primary/20 text-soc-primary' : 
                    inc.status === 'closed' ? 'bg-soc-success/20 text-soc-success' : 
                    'bg-soc-warning/20 text-soc-warning'
                  }`}>
                    {inc.status.toUpperCase()}
                  </span>
                  <button 
                    onClick={() => openCaseDetails(inc)}
                    className="text-soc-primary hover:text-blue-400 text-xs font-bold uppercase tracking-wider transition-colors"
                  >
                    Open Case &rarr;
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Case Details Modal */}
      {selectedCase && (
        <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 lg:p-12">
          <div className="bg-soc-panel border border-soc-border rounded-xl shadow-2xl w-full max-w-5xl h-full max-h-[90vh] flex flex-col overflow-hidden animate-in fade-in zoom-in duration-200">
            {/* Modal Header */}
            <div className="p-6 border-b border-soc-border bg-gradient-to-r from-soc-bg to-soc-panel flex items-start justify-between">
              <div className="flex items-start space-x-4">
                <div className="p-3 bg-soc-primary/10 rounded-lg text-soc-primary">
                  <Briefcase size={24} />
                </div>
                <div>
                  <div className="flex items-center space-x-3 mb-1">
                    <span className="text-xs font-mono text-soc-muted">{selectedCase.case_id}</span>
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase ${
                      selectedCase.severity === 'critical' ? 'bg-soc-critical text-white' : 'bg-soc-danger/20 text-soc-danger'
                    }`}>
                      {selectedCase.severity}
                    </span>
                  </div>
                  <h2 className="text-2xl font-bold text-soc-text">{selectedCase.title}</h2>
                  <p className="text-sm text-soc-muted mt-1 flex items-center">
                    <User size={14} className="mr-1" /> Assigned to: <span className="text-soc-primary ml-1">{selectedCase.analyst_assigned || 'Unassigned'}</span>
                  </p>
                </div>
              </div>
              <button onClick={() => setSelectedCase(null)} className="p-2 text-soc-muted hover:text-white hover:bg-soc-border rounded-full transition-all">
                <X size={24} />
              </button>
            </div>

            {/* Modal Body */}
            <div className="flex-1 flex overflow-hidden">
              {/* Left Column: Alerts and Context */}
              <div className="w-1/3 border-r border-soc-border bg-soc-bg/20 p-6 overflow-y-auto custom-scrollbar">
                <h4 className="text-xs font-semibold text-soc-muted uppercase tracking-widest mb-4">Case Overview</h4>
                <div className="space-y-4">
                  <div className="bg-soc-panel/50 border border-soc-border rounded-lg p-4">
                    <label className="text-xs text-soc-muted block mb-2 font-medium">Manage Status</label>
                    <div className="grid grid-cols-2 gap-2">
                       <button 
                        onClick={() => handleStatusUpdate(selectedCase.id, 'open')}
                        className={`text-xs py-2 rounded border transition-all ${selectedCase.status === 'open' ? 'bg-soc-primary text-white border-soc-primary shadow-lg shadow-soc-primary/20' : 'bg-soc-bg border-soc-border text-soc-muted hover:border-soc-muted'}`}
                       >
                        OPEN
                       </button>
                       <button 
                         onClick={() => handleStatusUpdate(selectedCase.id, 'closed')}
                         className={`text-xs py-2 rounded border transition-all ${selectedCase.status === 'closed' ? 'bg-soc-success text-white border-soc-success shadow-lg shadow-soc-success/20' : 'bg-soc-bg border-soc-border text-soc-muted hover:border-soc-muted'}`}
                       >
                        CLOSED
                       </button>
                    </div>
                  </div>

                  <div className="bg-soc-panel/50 border border-soc-border rounded-lg p-4">
                    <label className="text-xs text-soc-muted block mb-2 font-medium">L3 AI Assistant</label>
                    <button 
                      onClick={runAIAnalysis}
                      disabled={isAnalyzing}
                      className={`w-full py-2 rounded text-xs font-bold transition-all flex items-center justify-center space-x-2 ${isAnalyzing ? 'bg-soc-primary/20 text-soc-primary animate-pulse' : 'bg-gradient-to-r from-soc-primary to-blue-600 text-white shadow-lg shadow-soc-primary/20 hover:scale-[1.02]'}`}
                    >
                      {isAnalyzing ? (
                        <>
                          <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                          <span>TRIAGING...</span>
                        </>
                      ) : (
                        <>
                          <Shield size={14} />
                          <span>DEEP DIVE ANALYSIS</span>
                        </>
                      )}
                    </button>
                  </div>

                  <div className="bg-soc-panel/50 border border-soc-border rounded-lg p-4">
                    <label className="text-xs text-soc-muted block mb-2 font-medium">Evidence Context</label>
                    <div className="space-y-3">
                       <div className="flex justify-between text-xs">
                          <span className="text-soc-muted">Affected Host:</span>
                          <span className="text-soc-text font-mono tracking-tight">LAB-WS-09</span>
                       </div>
                       <div className="flex justify-between text-xs">
                          <span className="text-soc-muted">Threat Score:</span>
                          <span className={`${aiAnalysis?.score > 70 ? 'text-soc-critical' : 'text-soc-success'} font-bold`}>
                            {aiAnalysis ? `${aiAnalysis.score}%` : 'Pending'}
                          </span>
                       </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Right Column: Timeline & Notes */}
              <div className="flex-1 flex flex-col bg-soc-panel/30">
                <div className="flex-1 p-6 overflow-y-auto custom-scrollbar space-y-6">
                  {aiAnalysis ? (
                    <div className="space-y-6 animate-in fade-in duration-500">
                       {/* Kill Chain Visualization */}
                       <KillChainVisualization activeTactics={getTacticsFromMapping(aiAnalysis.mitre_mapping)} />

                       <div className="p-4 bg-soc-primary/5 border-l-4 border-soc-primary rounded-r-lg">
                          <h4 className="text-sm font-bold text-soc-primary mb-2 flex items-center">
                            <Shield size={16} className="mr-2" /> AI Forensic Summary
                          </h4>
                          <p className="text-sm text-soc-text leading-relaxed italic">"{aiAnalysis.technical_summary}"</p>
                       </div>

                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div className="bg-soc-bg/40 p-4 border border-soc-border rounded-lg">
                             <h5 className="text-[10px] font-bold text-soc-muted uppercase tracking-wider mb-3">Target Observation</h5>
                             <p className="text-xs text-soc-text leading-relaxed">{aiAnalysis.observation}</p>
                          </div>
                          <div className="bg-soc-bg/40 p-4 border border-soc-border rounded-lg">
                             <h5 className="text-[10px] font-bold text-soc-muted uppercase tracking-wider mb-3">MITRE Mapping</h5>
                             <div className="flex flex-wrap gap-2">
                                {aiAnalysis.mitre_mapping.map((m, i) => (
                                  <span key={i} className="px-2 py-1 bg-soc-panel text-[10px] rounded text-soc-primary border border-soc-primary/30">
                                    {m}
                                  </span>
                                ))}
                             </div>
                          </div>
                       </div>

                       <div className="bg-soc-danger/5 border border-soc-danger/20 p-4 rounded-lg">
                          <h5 className="text-xs font-bold text-soc-danger mb-3 uppercase flex items-center">
                             <AlertCircle size={14} className="mr-2" /> Recommended Remediation
                          </h5>
                          <ul className="space-y-2">
                             {aiAnalysis.recommendation.map((rec, i) => (
                               <li key={i} className="text-xs text-soc-text flex items-start">
                                  <span className="text-soc-danger mr-2">ΓÇó</span> {rec}
                               </li>
                             ))}
                          </ul>
                       </div>

                       <div className="flex items-center space-x-4">
                          <div className="flex-1 h-[1px] bg-soc-border"></div>
                          <span className="text-[10px] font-mono text-soc-muted uppercase">End of AI Intelligence Report</span>
                          <div className="flex-1 h-[1px] bg-soc-border"></div>
                       </div>
                    </div>
                  ) : (
                    <>
                      <h4 className="text-xs font-semibold text-soc-muted uppercase tracking-widest mb-4">Investigation Timeline</h4>
                      {(!selectedCase.notes || selectedCase.notes.length === 0) ? (
                        <div className="text-center py-12 text-soc-muted">
                          <Clock size={32} className="mx-auto mb-2 opacity-10" />
                          <p className="text-sm">No notes have been recorded for this case yet.</p>
                        </div>
                      ) : (
                        <div className="space-y-4">
                          {selectedCase.notes.map((note, idx) => (
                            <div key={idx} className="bg-soc-bg/40 border border-soc-border/50 rounded-lg p-4 relative group">
                              <div className="flex items-center justify-between mb-2">
                                <span className="text-xs font-bold text-soc-primary flex items-center">
                                  <User size={12} className="mr-1" /> {note.author}
                                </span>
                                <span className="text-[10px] text-soc-muted">
                                  {new Date(note.timestamp).toLocaleString()}
                                </span>
                              </div>
                              <p className="text-sm text-soc-text leading-relaxed">{note.content}</p>
                            </div>
                          ))}
                        </div>
                      )}
                    </>
                  )}
                </div>

                {/* Note Input */}
                <div className="p-6 border-t border-soc-border bg-soc-bg/30">
                  <div className="relative">
                    <textarea 
                      placeholder="Add analyst note or investigation update..."
                      className="w-full bg-soc-panel border border-soc-border rounded-lg p-4 pt-3 pb-12 text-sm text-soc-text focus:outline-none focus:border-soc-primary transition-all resize-none min-h-[120px]"
                      value={newNote}
                      onChange={(e) => setNewNote(e.target.value)}
                    />
                    <div className="absolute bottom-3 right-3 flex items-center space-x-3">
                       <span className="text-[10px] text-soc-muted uppercase font-bold tracking-tighter">Enter to send note</span>
                       <button 
                        disabled={submittingNote || !newNote.trim()}
                        onClick={submitNote}
                        className="bg-soc-primary text-white p-2 rounded-lg hover:bg-blue-600 transition-colors shadow-lg shadow-soc-primary/20 disabled:opacity-50"
                       >
                        <Send size={18} />
                       </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
      {/* New Case Creation Modal */}
      {isCreateModalOpen && (
        <div className="fixed inset-0 z-[110] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-soc-panel border border-soc-border rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-soc-border bg-gradient-to-r from-soc-bg to-soc-panel flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <Plus className="text-soc-primary" size={24} />
                <h2 className="text-xl font-bold text-soc-text">Create New Case</h2>
              </div>
              <button onClick={() => setIsCreateModalOpen(false)} className="text-soc-muted hover:text-white">
                <X size={20} />
              </button>
            </div>
            <form onSubmit={handleCreateCase} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-semibold text-soc-muted uppercase mb-2">Incident Title</label>
                <input 
                  type="text"
                  required
                  placeholder="e.g., Unauthorized Access on LAB-SRV-01"
                  className="w-full bg-soc-bg border border-soc-border rounded-lg p-3 text-sm text-soc-text focus:outline-none focus:border-soc-primary transition-all"
                  value={newCaseData.title}
                  onChange={(e) => setNewCaseData({...newCaseData, title: e.target.value})}
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-soc-muted uppercase mb-2">Severity</label>
                  <select 
                    className="w-full bg-soc-bg border border-soc-border rounded-lg p-3 text-sm text-soc-text focus:outline-none focus:border-soc-primary appearance-none cursor-pointer"
                    value={newCaseData.severity}
                    onChange={(e) => setNewCaseData({...newCaseData, severity: e.target.value})}
                  >
                    <option value="low">Low</option>
                    <option value="medium">Medium</option>
                    <option value="high">High</option>
                    <option value="critical">Critical</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-soc-muted uppercase mb-2">Assign Analyst</label>
                  <input 
                    type="text"
                    className="w-full bg-soc-bg border border-soc-border rounded-lg p-3 text-sm text-soc-text focus:outline-none focus:border-soc-primary"
                    value={newCaseData.analyst_assigned}
                    onChange={(e) => setNewCaseData({...newCaseData, analyst_assigned: e.target.value})}
                  />
                </div>
              </div>
              <div className="pt-4 flex space-x-3">
                <button 
                  type="button"
                  onClick={() => setIsCreateModalOpen(false)}
                  className="flex-1 px-4 py-2 bg-soc-bg border border-soc-border rounded-lg hover:bg-soc-border transition-colors text-sm font-medium"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  disabled={creatingCase || !newCaseData.title.trim()}
                  className="flex-1 px-4 py-2 bg-soc-primary text-white rounded-lg hover:bg-blue-600 transition-colors text-sm font-medium shadow-lg shadow-soc-primary/20 disabled:opacity-50"
                >
                  {creatingCase ? 'Creating...' : 'Launch Incident'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Search, Filter, Download } from 'lucide-react';

export default function LogManagement() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch logs from backend
    fetch('http://localhost:8000/api/logs')
      .then(res => res.json())
      .then(data => {
        setLogs(data);
        setLoading(false);
      })
      .catch(err => {
        setLoading(false);
      });
  }, []);

  const exportLogsToJSON = () => {
    if (logs.length === 0) return;

    // Create a Blob from the JSON data
    const jsonString = JSON.stringify(logs, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });

    // Create a temporary DOM element to trigger the download
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `soc_logs_export_${new Date().toISOString().slice(0, 10)}.json`;

    // Append -> click -> remove
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-soc-text">Log Explorer</h2>
          <p className="text-sm text-soc-muted mt-1">Search and filter ingested security logs</p>
        </div>
        <div className="flex space-x-3">
          <button className="flex items-center px-4 py-2 bg-soc-panel border border-soc-border rounded hover:bg-soc-border transition-colors text-sm">
            <Filter size={16} className="mr-2" /> Filter
          </button>
          <button 
            onClick={exportLogsToJSON}
            disabled={logs.length === 0}
            className={`flex items-center px-4 py-2 rounded transition-colors text-sm shadow-lg ${logs.length === 0 ? 'bg-soc-border text-soc-muted cursor-not-allowed shadow-none' : 'bg-soc-primary text-white hover:bg-blue-600 shadow-soc-primary/20'}`}
          >
            <Download size={16} className="mr-2" /> {logs.length === 0 ? 'No Data to Export' : 'Export JSON'}
          </button>
        </div>
      </div>

      <div className="bg-soc-panel border border-soc-border rounded-lg shadow-lg overflow-hidden">
        <div className="p-4 border-b border-soc-border flex items-center bg-soc-bg/50">
          <Search size={20} className="text-soc-muted mr-3" />
          <input 
            type="text" 
            placeholder="Search logs (e.g., process_name:powershell.exe)..." 
            className="w-full bg-transparent border-none outline-none text-soc-text placeholder-soc-muted"
          />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm whitespace-nowrap">
            <thead className="bg-soc-bg text-soc-muted border-b border-soc-border">
              <tr>
                <th className="px-6 py-4 font-medium">Timestamp</th>
                <th className="px-6 py-4 font-medium">Event ID</th>
                <th className="px-6 py-4 font-medium">Computer</th>
                <th className="px-6 py-4 font-medium">Process</th>
                <th className="px-6 py-4 font-medium">User</th>
                <th className="px-6 py-4 font-medium">Source IP</th>
                <th className="px-6 py-4 font-medium">Event Type</th>
                <th className="px-6 py-4 font-medium">Severity</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-soc-border">
              {loading ? (
                <tr><td colSpan="8" className="px-6 py-8 text-center text-soc-muted">Loading logs...</td></tr>
              ) : logs.length === 0 ? (
                <tr><td colSpan="8" className="px-6 py-8 text-center text-soc-muted">No logs found in the database. Run the simulator to generate some.</td></tr>
              ) : (
                logs.map(log => {
                  // Ensure UTC parsing for correct local time mapping
                  const d = new Date(log.timestamp.endsWith('Z') ? log.timestamp : log.timestamp + 'Z');
                  const timeString = d.toLocaleString(undefined, {
                    year: 'numeric', month: 'short', day: 'numeric', 
                    hour: '2-digit', minute: '2-digit', second: '2-digit'
                  });
                  return (
                    <tr key={log.id} className="hover:bg-soc-bg/40 cursor-pointer transition-colors">
                      <td className="px-6 py-4 text-soc-muted font-mono text-xs whitespace-nowrap">{timeString}</td>
                      <td className="px-6 py-4">{log.event_id || '-'}</td>
                      <td className="px-6 py-4 text-soc-text">{log.details?.host || log.details?.Computer || '-'}</td>
                      <td className="px-6 py-4">{log.process_name || '-'}</td>
                      <td className="px-6 py-4">{log.user || '-'}</td>
                      <td className="px-6 py-4 text-blue-400 font-mono">{log.ip_address || '-'}</td>
                      <td className="px-6 py-4">{log.event_type || '-'}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded text-xs font-medium bg-soc-bg border border-soc-border
                          ${log.severity?.toLowerCase() === 'high' || log.severity?.toLowerCase() === 'critical' ? 'text-soc-danger border-soc-danger/30' : 
                            log.severity?.toLowerCase() === 'medium' ? 'text-soc-warning border-soc-warning/30' : 'text-soc-muted'}`}>
                          {log.severity ? log.severity.toUpperCase() : 'LOW'}
                        </span>
                      </td>
                    </tr>
                  )
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { Shield, Lock, User } from 'lucide-react';

export default function Login({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const endpoint = isRegistering ? 'http://localhost:8000/api/auth/register' : 'http://localhost:8000/api/auth/login';
      const payload = isRegistering 
        ? { username, password, alert_email: email } 
        : { username, password };

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (!response.ok) {
        const errData = await response.json();
        throw new Error(errData.detail || (isRegistering ? 'Registration failed' : 'Invalid credentials'));
      }

      onLogin(username);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-soc-bg flex items-center justify-center p-4">
      <div className="max-w-md w-full">
        <div className="text-center mb-8">
